INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-02286', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '為了協助孕婦順利產下健康的嬰兒，社工人員應對懷孕期有所了解，以進行評估或提供孕婦服務，下列 何者非屬懷孕期保護因子（protective factors）？ 參與產前照顧方案    意外事故預防 懷孕年齡小於18歲或大於35歲  參與營養補助方案', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02287', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '怡婷是一位20歲的單親母親，她向社會工作師抱怨她照顧2歲孩子的困難。她表示自己從生下孩子之後 根本沒辦法出去玩，只要她一離開，孩子就哭鬧，就算回到身邊也不一定會停止哭泣，有時候甚至會用 小拳頭撲打怡婷，怡婷雖然不感覺疼痛，但是感到不耐煩，有時忍不住也會對孩子發脾氣。社會工作師 若依據依附理論評估，孩子對怡婷可能是屬於那一種依附關係？ 安全型依附（secure attachment） 焦慮型依附（anxious attachment） 迴避型依附（avoidant attachment） 無定向的不安全反應（insecure disoriented response）', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02288', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Baumrind 是父母管教的著名學者，投注相當多的心力在於研究父母管教。對於父母管教，下列那一個有 關父母管教方式、管教特質及對兒童影響的敘述正確？ 威權型的父母對孩子嚴格，且過於嚴厲，因此和孩子很少互動；此種教養方式往往會使孩子具有攻擊性 自主型的父母對孩子鼓勵很少，管教鬆散，因此常使孩子抗壓性低且容易衝動 寬大縱容型的父母少要求孩子，卻很投入孩子生活，但也常使孩子自我控制低、影響孩子的人際關係 寬大疏忽型的父母對孩子常會給予尊重自主，但設限很多，能使孩子自我控制能力和認知能力佳', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02289', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者符合對於社會角色採取能力的描述？ 強化自我中心思考    與道德發展無關，不影響個人對他人觀點的覺知 是合作、利他等社會行為發展的先決條件  社會認知的能力是天生的，不受年齡影響', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02290', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '2014年一則電視新聞時段播放的影片，內容是一個爸爸在文具店拿起「愛的小手」打算購買，年約4～5 歲的孩子看到之後就一直用童稚的聲音，哭吵著叫爸爸不要買，「不要啦，這個很貴的啦」、「你不要 買啦」，最後甚至哭著喊說：「你不要買啦，這個很貴的」、「不要啦，很危險的」、「這個不能玩啦」， 孩子緊張的模樣受到網友瘋狂轉傳，紛紛表示這個孩子「超萌」、「超口愛」。倘若你是一位兒童保護 社會工作師，你對這個孩子看到爸爸要買「愛的小手」的反應，下列何者不屬於合理的判斷？ 這個年齡階段的孩童對商品價格已經具備判斷能力，會一直說東西很貴，是考量爸爸購買能力的建議 這個孩子可能曾經有被「愛的小手」打過的經驗 這個孩子可能具有創傷後壓力症（posttraumatic stress disorder, PTSD） 這個父親對於孩子的害怕感受欠缺同理', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02291', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「對自己的未來沒有任何想法，也不想要探索或了解可能的選擇；對於父母或重要他人的建議也不接受， 對許多重要態度、價值觀等都還沒進行承諾，但也還沒經歷認同危機。」若是依照Marcia的認同理論而 言，這位青年可能在那一個自我認同發展階段？ 認同迷失（identity diffusion）  他主定向（identity foreclosure） 延期未定（identity moratorium）  認同達成（identity achievement）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02292', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「青少年常認為很多人會關注他們的一言一行，並且覺得自己的一切相當重要，是世界的焦點。」這樣 的感受符合何種理論的敘述？ 自我中心  鏡中自我  自我認同  自我歸因', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02293', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關性騷擾（sexual harassment）的描述，下列何者錯誤？ 是指不受歡迎的性接近、性要求或其他具有性意味的言語或肢體動作等 性騷擾往往與不平等的權力與施壓等元素有關 受害人幾乎都是女性，鮮少有男性因為性騷擾而感到困擾 對特定性別語言上的評論也可能構成性騷擾，如指稱女員工情緒差「一定是每個月的那個來了」', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02294', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '小明加入一個幫派，這個幫派幫規要求成員要保護地盤，對於外來挑釁的回應要視死如歸，該幫派成員 令當地民眾避之唯恐不及。若依據莫拉萊斯（Morales）（2002）對幫派的分類，小明參與的幫派有可能 是那一種？ 犯罪型（criminal）    衝突型（conflict） 逃避型（retreatist gangs）  神秘團體（occult groups）', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02295', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Sternberg的愛情三角理論，認為愛情包含那三個元素？ 親密、激情、承諾    生理、心理、精神  慾望、期待、承諾  探索、迷戀、孤獨', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02296', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '對於近年來中年勞動者的工作模式敘述，下列何者正確？ 失業對中年勞動者而言非危險因子 中年勞工的工作流動性非常低 工作和退休的界線明確且清楚，多數人退休後並不會繼續工作 中年勞工繼續接受教育是常見且普遍的現象', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02297', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '志強是一名55歲的關廠工人，由於遭到資方惡意積欠工資又求償無門，內心氣忿難平，陸陸續續透過親 友介紹工作均未能順利，志強很希望社會工作師協助他儘快找到適當的工作。若就舒伯（Super）的生涯 發展理論觀之，志強目前是處在生涯發展的那個時期？ 建立期（establishment）  探索期（exploration） 衰退期（decline）    維持期（maintenance）', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02298', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '成功老化的關鍵，不包含下列那一個？ 避免疾病        生活積極承諾 維持高認知與身體功能   選擇居住都會區', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02299', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「卓越老年的觀點認為，人類的發展會延伸到老年期，且不會因為老化而停止。」這樣的說法屬於那個 理論對老年期的應用？ 撤退理論      連續理論  社會建構理論  社會交換理論', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02300', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會工作師鼓勵長期居住在養護照顧機構的老人參與每週一次的生命回顧團體，下列那一個敘述錯誤？ 有助於老人達到生命的統整 為了避免觸景傷情，不適合運用此方法協助已喪偶老人 可以在團體中探討死亡的議題 老人在生命晚期階段總結過去的生活是有意義的', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02301', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '庫伯勒蘿思（Kübler-Ross）提出悲傷模式，認為一般人面對死亡階段，原則上是以下列那一種順序發展？ 否認－討價還價－沮喪－憤怒－接納  憤怒－否認－沮喪－討價還價－接納 否認－憤怒－討價還價－沮喪－接納  沮喪－否認－憤怒－討價還價－接納', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02302', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社工人員依據性別平等教育法及其相關法規之規定，對校園性別事件的處理與調查敘述，下列何者正確？ 社工人員在輔導受害人時，為維護受害人權益，應擔任調查小組成員 為了確認事件的真實性，調查小組、輔導團隊、行政處理人員都應該要反覆詢問相關當事人事件發生 的經過 校園性別事件的調查與處理應顧及受害學生的權益與感受，在其不願意繼續調查時，可以暫時擱置， 直到受害學生願意配合為止 調查小組以3人或5人為主，女性應占二分之一，且應有三分之一為主管單位認證之調查人才庫成員', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02303', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '玉珮在一家婦女福利機構工作 8 年多了，與她同期甚至更晚期進入機構的男同事都已經升遷擔任主管職 務，她在這次新任主管名單當中仍未獲拔擢。她深入分析主管性別後發現，近九成是男性。玉佩認為在 這個以服務婦女且工作人員多數是女性的社會福利機構，男性主管比例過高，是不公平的現象。這個機 構可能有何種現象？ 制度性歧視（institutional discrimination）  政黨政治運作 女性員工普遍無意願擔任主管職務  採「非性別主義」拔擢主管', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02304', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '發生校園霸凌狀況時，依據校園霸凌防制準則的規範，下列何者正確？ 依據該準則所稱之校園霸凌，僅限於發生於校園內的霸凌行為 學校面對被霸凌或曾有霸凌行為或傾向的學生，可以請家長帶回家中自行輔導與管教，不需進行處遇 疑似校園霸凌事件的被霸凌人可以向學校申請調查，學校應於3日內召開防制校園霸凌因應小組會議， 並於受理後2個月內處理完畢 媒體報導的疑似校園霸凌事件，因無申訴人，學校並不需要進行調查與處理', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02305', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '老人由於身心衰退，容易成為受虐待的族群，下列對老人生活與保護相關的敘述，何者錯誤？ 絕大多數的老人是在長期照顧機構中接受照顧 老人虐待的加害人（施虐者）可能是機構照顧人員，也可能是老人自己的親生子女 由於老人體力與靈活度降低，容易成為搶劫、詐騙等犯罪的被害者 通報老人受虐人數與實際受虐人數相較，可能只是冰山之一角', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02306', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對於性別影響評估的敘述，何者錯誤？ 在規劃法案、政策、計畫、方案、策略時，將「性別」當作一個必要元素 考量不同年齡族群的觀點及對各類人際關係發展的影響 行政院各機關之中長程個案計畫及法案，均需進行性別影響評估 性別影響評估係由一系列問題所組成的測量工具', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02307', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對於Piaget的認知發展理論的描述，何者正確？ 依照年齡分為八個階段，人在對應的年齡就會自然進入該階段 2到7歲的兒童認知發展為感覺動作期，兒童可以透過感官經驗來探索世界 國小階段（7到11歲）的兒童認知發展為運思前期，兒童可以透過抽象概念來進行思考 12歲以上青少年的認知發展在形式運思期，具有可以學習數學代數、幾何等抽象邏輯推理能力', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02308', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '物質濫用對人類行為及生活產生嚴重的影響，常被濫用的物質包括鎮定劑、安定劑、止痛劑及興奮劑， 下列那一種物質不屬於興奮劑的作用？ 酒精  安非他命  大麻  海洛因', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02309', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會存在貧窮及收入在貧窮線（poverty line）以下的問題，下列對「貧窮」的敘述，何者錯誤？ 大多數的貧窮或窮人都是因為個人的能力低落或努力不足而造成 社會上的性別歧視可能導致貧窮 貧窮可能一代一代傳遞，成為貧窮惡性循環 某些功能主義學者認為貧窮具有一定的功能，如果沒有窮人，一些卑微艱苦的工作就沒有人去做了', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02310', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '同性戀者從認知自己的性取向到公開承認同性戀傾向的過程為「出櫃」。一般而言，出櫃需要歷經四個 階段，其順序為何？ 認識圈內人－自我坦承－向親友坦承－出櫃  自我坦承－認識圈內人－向親友坦承－出櫃 認識圈內人－向親友坦承－自我坦承－出櫃  自我坦承－向親友坦承－認識圈內人－出櫃', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
